#!/usr/bin/env python3
"""Generate 200+ pages for 7 language sections: R, PowerShell, CSS, VBA, Objective-C, Groovy, Erlang."""
import os

BASE_DIR = os.path.join(os.path.dirname(os.path.abspath(__file__)), "..", "content", "languages")

def get_existing(lang_dir):
    s = set()
    if not os.path.isdir(lang_dir): return s
    for f in os.listdir(lang_dir):
        if f.endswith(".md") and f != "_index.md":
            s.add(f[:-3])
    return s

def pg(slug, title, desc, lang, causes, fixes, examples):
    return f"""---
title: "[Solution] {title}"
description: "{desc}"
languages: ["{lang}"]
error-types: ["language-error"]
severities: ["error"]
---

# {title}

{desc}

### Common Causes
{causes}

### How to Fix
{fixes}

### Examples
{examples}
"""

def write_all(lang_dir, lang, topics, existing):
    written = skipped = 0
    os.makedirs(lang_dir, exist_ok=True)
    for slug, title, desc, causes, fixes, examples in topics:
        if slug in existing: skipped += 1; continue
        with open(os.path.join(lang_dir, slug + ".md"), "w") as f:
            f.write(pg(slug, title, desc, lang, causes, fixes, examples))
        written += 1
    return written, skipped


# Topic helper - generates compact body from params
def T(slug, title, desc, causes, fixes, examples):
    return (slug, title, desc, causes, fixes, examples)

