# =============================================================================
# Main Execution
# =============================================================================
if __name__ == "__main__":
    all_languages = [
        (R_DIR, R_LANG, R_TOPICS),
        (PS_DIR, PS_LANG, PS_TOPICS),
        (CSS_DIR, CSS_LANG, CSS_TOPICS),
        (VBA_DIR, VBA_LANG, VBA_TOPICS),
        (OBJC_DIR, OBJC_LANG, OBJC_TOPICS),
        (GROOVY_DIR, GROOVY_LANG, GROOVY_TOPICS),
        (ERLANG_DIR, ERLANG_LANG, ERLANG_TOPICS),
    ]
    
    total_written = 0
    for lang_dir, lang, topics in all_languages:
        existing = get_existing(lang_dir)
        written, skipped = write_all(lang_dir, lang, topics, existing)
        total_written += written
        print(f"{lang}: wrote {written} new pages ({skipped} skipped, {len(existing)} existing, total now {written + len(existing)})")
    
    print(f"\nTotal new pages written: {total_written}")
